class.description:
Wraps [PolygonTriangulation] and returns results as [PackedVector3Array] and [PackedInt32Array] instead of raw C pointers. Use this when you need direct control over DMWT parameters; use [CassieTriangulator] for the full pmp-refined pipeline.

[codeblock]
var pt := PolygonTriangulationGodot.create(boundary_points, normals)
pt.set_cost_weights(0.0, 1.0, 0.0, 0.0, 0.5)  # edge + worst-dihedral
if pt.preprocess() and pt.triangulate():
    var mesh := pt.get_mesh()
    print("cost: ", pt.get_optimal_cost())
[/codeblock]
